import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const Booking = () => {
    const navigate = useNavigate();
    const [selectedCab, setSelectedCab] = useState('Mini');

    return (
        <div style={containerStyle}>
            {/* Sidebar remains the same for consistency */}
            <aside style={sidebarStyle}>
                <h1 style={logoStyle}>Ucab</h1>
                <nav style={{ flex: 1 }}>
                    <div onClick={() => navigate('/profile')} style={navItemStyle}>👤 Profile</div>
                    <div onClick={() => navigate('/booking')} style={activeNavItemStyle}>🚗 Book a Ride</div>
                    <div onClick={() => navigate('/payments')} style={navItemStyle}>💳 Payments</div>
                    <div onClick={() => navigate('/support')} style={navItemStyle}>⚙️ Support</div>
                </nav>
                <div onClick={() => navigate('/')} style={logoutStyle}>Logout</div>
            </aside>

            <main style={mainAreaStyle}>
                <div style={contentGrid}>
                    
                    {/* --- MODERN BOOK YOUR RIDE SECTION --- */}
                    <div style={formCard}>
                        <h3 style={cardTitle}>BOOK YOUR RIDE</h3>
                        
                        <div style={inputWrapper}>
                            <label style={labelStyle}>Pickup Point</label>
                            <input type="text" placeholder="Enter pickup address..." style={inputStyle} />
                        </div>

                        <div style={inputWrapper}>
                            <label style={labelStyle}>Destination</label>
                            <input type="text" placeholder="Enter destination..." style={inputStyle} />
                        </div>

                        <h4 style={subTitle}>Select Cab Class</h4>
                        <div style={cabGrid}>
                            <div 
                                onClick={() => setSelectedCab('Mini')} 
                                style={selectedCab === 'Mini' ? activeCabBox : cabBox}
                            >
                                <div style={iconCircle}>🚕</div>
                                <span style={cabName}>Ucab Mini</span>
                                <span style={priceTag}>$25.00</span>
                            </div>

                            <div 
                                onClick={() => setSelectedCab('Sedan')} 
                                style={selectedCab === 'Sedan' ? activeCabBox : cabBox}
                            >
                                <div style={iconCircle}>🚙</div>
                                <span style={cabName}>Ucab Sedan</span>
                                <span style={priceTag}>$35.00</span>
                            </div>
                        </div>

                        <button style={confirmBtn}>CONFIRM RIDE</button>
                    </div>

                    {/* --- MAP SECTION --- */}
                    <div style={mapCard}>
                        <iframe 
                            title="map"
                            width="100%" 
                            height="100%" 
                            frameBorder="0" 
                            src="https://www.openstreetmap.org/export/embed.html?bbox=77.0,28.4,77.3,28.7&layer=mapnik"
                            style={{ borderRadius: '20px' }}
                        />
                    </div>

                </div>
            </main>
        </div>
    );
};

// --- STYLES FOR THE MODIFICATION ---
const containerStyle = { display: 'flex', height: '100vh', backgroundColor: '#f4f7fe', fontFamily: 'Inter, sans-serif' };
const sidebarStyle = { width: '260px', backgroundColor: '#fff', padding: '30px', borderRight: '1px solid #e2e8f0' };
const logoStyle = { color: '#0052cc', fontSize: '28px', fontWeight: 'bold', marginBottom: '40px' };
const navItemStyle = { padding: '12px', cursor: 'pointer', color: '#64748b', borderRadius: '10px', marginBottom: '5px' };
const activeNavItemStyle = { ...navItemStyle, backgroundColor: '#f0f7ff', color: '#0052cc', fontWeight: '600' };
const logoutStyle = { marginTop: 'auto', color: '#ef4444', cursor: 'pointer', padding: '12px' };

const mainAreaStyle = { flex: 1, padding: '40px' };
const contentGrid = { display: 'flex', gap: '30px', height: '85vh' };

// Card Styling (The part you wanted modified)
const formCard = { 
    width: '400px', 
    backgroundColor: '#fff', 
    borderRadius: '24px', 
    padding: '30px', 
    boxShadow: '0 10px 25px rgba(0,0,0,0.05)',
    display: 'flex',
    flexDirection: 'column'
};

const cardTitle = { fontSize: '14px', letterSpacing: '1px', color: '#94a3b8', marginBottom: '25px', fontWeight: '700' };
const inputWrapper = { marginBottom: '20px' };
const labelStyle = { display: 'block', fontSize: '13px', color: '#475569', marginBottom: '8px', fontWeight: '600' };
const inputStyle = { width: '100%', padding: '14px', borderRadius: '12px', border: '1.5px solid #e2e8f0', outline: 'none', backgroundColor: '#f8fafc' };

const subTitle = { fontSize: '15px', color: '#1e293b', marginBottom: '15px' };
const cabGrid = { display: 'flex', gap: '15px', marginBottom: '30px' };

const cabBox = { 
    flex: 1, padding: '15px', borderRadius: '16px', border: '1.5px solid #e2e8f0', 
    textAlign: 'center', cursor: 'pointer', transition: '0.3s' 
};
const activeCabBox = { ...cabBox, borderColor: '#0052cc', backgroundColor: '#f0f7ff' };

const iconCircle = { fontSize: '24px', marginBottom: '5px' };
const cabName = { display: 'block', fontWeight: '700', fontSize: '14px' };
const priceTag = { fontSize: '12px', color: '#64748b' };

const confirmBtn = { 
    width: '100%', padding: '16px', backgroundColor: '#10b981', color: '#fff', 
    border: 'none', borderRadius: '12px', fontWeight: 'bold', cursor: 'pointer',
    boxShadow: '0 4px 12px rgba(16, 185, 129, 0.2)'
};

const mapCard = { flex: 1, borderRadius: '24px', overflow: 'hidden', boxShadow: '0 10px 25px rgba(0,0,0,0.05)' };

export default Booking;
